	resultMap := make\(map[string]Component\)

	// Define recursive function to populate resultMap - used by both CVE and root component processing
	var addComponentToMap func\(Component\)
	addComponentToMap = func\(comp Component\) {
		if _, exists := resultMap[comp.Uid]; exists {
			return // Already added
		}
		resultMap[comp.Uid] = comp
		logging.Debug\("Component found: UID: %s, Name: %s, PURL: %s, CVE: %s", comp.Uid, comp.Name, comp.Purl, comp.CveID\)

		// Recursively add dependencies
		for _, dep := range comp.DependsOn {
			addComponentToMap\(Component{
				Uid:        dep.Uid,
				Name:       dep.Name,
				Purl:       dep.Purl,
				CveID:      "",
				Version:    dep.Version,
				Vulnerable: dep.Vulnerable,
				BomRef:     dep.BomRef,
				Reference:  dep.Reference,
			}\)
		}

		// Recursively add reverse dependencies
		for _, dep := range comp.ReverseDependsOn {
			addComponentToMap\(Component{
				Uid:        dep.Uid,
				Name:       dep.Name,
				Purl:       dep.Purl,
				CveID:      "",
				Version:    dep.Version,
				Vulnerable: dep.Vulnerable,
				BomRef:     dep.BomRef,
				Reference:  dep.Reference,
			}\)
		}
	}

	for cveID, purl := range cvePurlMap {
		logging.Debug\("Querying for CVE: %s and PURL: %s", cveID, purl\)
		variables := map[string]string{"$purl": purl, "$cveID": cveID}

		txn := client.NewTxn\(\)
		resp, err := txn.QueryWithVars\(context.Background\(\), query, variables\)
		txn.Discard\(ctx\) // Immediately discard after query

		if err != nil {
			logging.Error\("Query failed for CVE: %s and PURL: %s", cveID, purl\)
			return nil, err
		}

		var result QueryResult
		if err := json.Unmarshal\(resp.GetJson\(\), &result\); err != nil {
			logging.Error\("Failed to unmarshal response for CVE: %s and PURL: %s", cveID, purl\)
			return nil, err
		}

		logging.Debug\("QueryResult: %+v", result\)

		for _, component := range result.Component {
			if len\(component.DependsOn\) == 0 {
				component.DependsOn = []DependsOn{{Name: "No dependencies found"}}
			}
			if len\(component.ReverseDependsOn\) == 0 {
				component.ReverseDependsOn = []DependsOn{{Name: "No dependencies found"}}
			}
			addComponentToMap\(component\)
		}
	}
